1: module rst_wrapper #(
2:     parameter int unsigned AXI_ADDR_WIDTH = 64,
3:     parameter int unsigned AXI_DATA_WIDTH = 64,
4:     parameter int unsigned AXI_ID_WIDTH   = 10
5: )(
6:            clk_i,
7:            rst_ni,
8:            reglk_ctrl_i,
9:            acct_ctrl_i,
10:            debug_mode_i,
11:            axi_req_i, 
12:            axi_resp_o,
13: 		   
14: 		   rst_1,
15: 		   rst_2,
16: 		   rst_3,
17: 		   rst_4,
18: 		   rst_5,
19: 		   rst_6,
20: 		   rst_7,
21: 		   rst_8,
22: 		   rst_9,
23: 		   rst_10,
24: 		   rst_11,
25: 		   rst_13
26:        );
27: 
28:     input  logic                   clk_i;
29:     input  logic                   rst_ni;
30:     input logic [7 :0]             reglk_ctrl_i; // register lock values
31:     input logic                    acct_ctrl_i;
32:     input logic                    debug_mode_i;
33:     input  ariane_axi::req_t       axi_req_i;
34:     output ariane_axi::resp_t      axi_resp_o;
35: 
36: 	output logic rst_1;
37: 	output logic rst_2;
38: 	output logic rst_3;
39: 	output logic rst_4;
40: 	output logic rst_5;
41: 	output logic rst_6;
42: 	output logic rst_7;
43: 	output logic rst_8;
44: 	output logic rst_9;
45: 	output logic rst_10;
46: 	output logic rst_11;
47: 	output logic rst_13;
48: 
49: 	logic rst_12;
50: 
51: 	// internal signals
52: 	logic start;
53: 
54: 	logic [4:0]  rst_id;
55: 	logic [13:0] rst_mem;
56: 
57: 	// reset logic: if start is high, set to rst memory, otherwise keep at default
58: 	assign rst_1 = rst_mem[1]; // AES0
59: 	assign rst_2 = rst_mem[2]; // AES1
60: 	assign rst_3 = rst_mem[3]; // SHA256
61: 	assign rst_4 = rst_mem[4]; // HMAC
62: 	assign rst_5 = rst_mem[5]; // PKT
63: 	assign rst_6 = rst_mem[6]; // ACCT
64: 	assign rst_7 = rst_mem[7]; // UART
65: 	assign rst_8 = rst_mem[8]; // DMA
66: 	assign rst_9 = rst_mem[9]; // REGLK
67: 	assign rst_10 = rst_mem[10]; // RNG
68: 	assign rst_11 = rst_mem[11]; // AES2
69: 	assign rst_12 = rst_mem[12]; // RST_CTRL
70: 	assign rst_13 = rst_mem[13]; // RSA
71: 
72: // rst vector logic
73: always @(posedge clk_i) begin
74: 	if (~rst_ni || rst_12) begin
75: 			rst_mem <= 0;
76: 	end else if (start) begin
77: 		case (rst_id)
78: 			0: // ROM
79: 				rst_mem[0] <= 1;
80: 			1: // AES0
81: 				rst_mem[1] <= 1;
82: 			2: // AES1
83: 				rst_mem[2] <= 1;
84: 			3: // SHA256
85: 				rst_mem[3] <= 1;
86: 			4: // HMAC
87: 				rst_mem[4] <= 1;
88: 			5: // PKT
89: 				rst_mem[5] <= 1;
90: 			6: // ACCT
91: 				rst_mem[6] <= 1;
92: 			7: // UART	
93: 				rst_mem[7] <= 1;
94: 			8: // DMA
95: 				rst_mem[8] <= 1;
96: 			9: // REGLK
97: 				rst_mem[9] <= 1;
98: 			10: // RNG
99: 				rst_mem[10] <= 1;
100: 			11: // AES2
101: 				rst_mem[11] <= 1;
102: 			12: // RST_CTRL - the peripheral itself
103: 				rst_mem[12] <= 1;
104: 			13: // RSA
105: 				rst_mem[13] <= 1;
106: 		endcase
107: 	end else begin
108: 		rst_mem <= 0;
109: 	end
110: end
111: 
112: 
113: // signals from AXI 4 Lite
114: logic [AXI_ADDR_WIDTH-1:0] address;
115: logic                      en, en_acct;
116: logic                      we;
117: logic [63:0] wdata;
118: logic [63:0] rdata;
119: 
120: ///////////////////////////////////////////////////////////////////////////
121:     // -----------------------------
122:     // AXI Interface Logic
123:     // -----------------------------
124:     axi_lite_interface #(
125:         .AXI_ADDR_WIDTH ( AXI_ADDR_WIDTH ),
126:         .AXI_DATA_WIDTH ( AXI_DATA_WIDTH ),
127:         .AXI_ID_WIDTH   ( AXI_ID_WIDTH    )   
128:     ) axi_lite_interface_i (
129:         .clk_i      ( clk_i      ),
130:         .rst_ni     ( rst_ni     ),
131:         .axi_req_i  ( axi_req_i  ),
132:         .axi_resp_o ( axi_resp_o ),
133:         .address_o  ( address    ),
134:         .en_o       ( en_acct    ),
135:         .we_o       ( we         ),
136:         .data_i     ( rdata      ),
137:         .data_o     ( wdata      )
138:     );
139: 
140:     assign en = en_acct && acct_ctrl_i; 
